import { useEffect, useRef, useState } from 'react';
import './Skills.css';

const SKILLS = [
  {
    category: 'Frontend',
    icon: '</>',
    color: '#06B6D4',
    bg: 'linear-gradient(135deg, #0e7490, #06B6D4)',
    desc: 'Fast, accessible, pixel-perfect interfaces.',
    items: ['React', 'TypeScript', 'Next.js', 'HTML/CSS', 'TailwindCSS'],
  },
  {
    category: 'Backend',
    icon: '⚙',
    color: '#7C3AED',
    bg: 'linear-gradient(135deg, #4c1d95, #7C3AED)',
    desc: 'Scalable APIs, databases, and server-side logic.',
    items: ['Node.js', 'Python', 'FastAPI', 'PostgreSQL', 'Redis'],
  },
  {
    category: 'Fintech',
    icon: '₦',
    color: '#10B981',
    bg: 'linear-gradient(135deg, #065f46, #10B981)',
    desc: 'Payment flows, KYC, escrow, and fraud signals.',
    items: ['Paystack', 'Flutterwave', 'KYC Flows', 'Escrow', 'Fraud Signals'],
  },
  {
    category: 'Video',
    icon: '▶',
    color: '#F59E0B',
    bg: 'linear-gradient(135deg, #92400e, #F59E0B)',
    desc: 'Commercial edits, colour grading, motion graphics.',
    items: ['Premiere Pro', 'After Effects', 'DaVinci Resolve', 'Colour Grading', 'Motion Graphics'],
  },
  {
    category: 'Tools',
    icon: '⌥',
    color: '#EC4899',
    bg: 'linear-gradient(135deg, #831843, #EC4899)',
    desc: 'The glue that holds every project together.',
    items: ['Git', 'Docker', 'Figma', 'Supabase', 'Firebase'],
  },
];

export default function Skills() {
  const titleRef = useScrollReveal();
  const [active, setActive] = useState(0);

  return (
    <section className="skills section" id="skills">
      <div className="section__inner">
        <div className="section__label">Toolkit</div>
        <h2 className="section__heading reveal" ref={titleRef}>
          Skills &amp; <span className="gradient-text">technologies</span>
        </h2>

        <div className="skills__cubes">
          {SKILLS.map((s, i) => (
            <SkillCube
              key={s.category}
              skill={s}
              isActive={active === i}
              onClick={() => setActive(i)}
            />
          ))}
        </div>

        <div className="skills__panel" key={active}>
          <p className="skills__panel-cat" style={{ color: SKILLS[active].color }}>
            {SKILLS[active].category}
          </p>
          <p className="skills__panel-desc">{SKILLS[active].desc}</p>
          <div className="skills__chips">
            {SKILLS[active].items.map((item, i) => (
              <span
                key={item}
                className="skills__chip"
                style={{
                  animationDelay: `${i * 0.07}s`,
                  '--chip-color': SKILLS[active].color,
                }}
              >
                {item}
              </span>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
}

function SkillCube({ skill, isActive, onClick }) {
  const ref = useScrollReveal();

  return (
    <div
      className={`cube-wrap reveal${isActive ? ' cube-wrap--active' : ''}`}
      ref={ref}
      onClick={onClick}
      role="button"
      tabIndex={0}
      onKeyDown={e => e.key === 'Enter' && onClick()}
    >
      <div className="cube" style={{ '--cube-color': skill.color, '--cube-bg': skill.bg }}>
        {/* Front */}
        <div className="cube__face cube__face--front">
          <span className="cube__icon">{skill.icon}</span>
          <span className="cube__label">{skill.category}</span>
        </div>
        {/* Back */}
        <div className="cube__face cube__face--back">
          <span className="cube__icon">{skill.icon}</span>
          <span className="cube__label">{skill.category}</span>
        </div>
        {/* Top */}
        <div className="cube__face cube__face--top" />
        {/* Bottom */}
        <div className="cube__face cube__face--bottom" />
        {/* Left */}
        <div className="cube__face cube__face--left">
          <span className="cube__icon cube__icon--sm">{skill.icon}</span>
        </div>
        {/* Right */}
        <div className="cube__face cube__face--right">
          <span className="cube__icon cube__icon--sm">{skill.icon}</span>
        </div>
      </div>
      <p className="cube-wrap__name">{skill.category}</p>
    </div>
  );
}
